    double flow{0.0f};
    auto const &node_data = node_match[ntk.node_to_index(n)];

    uint8_t ctr = 0u;
    for (auto leaf : cut) {
      uint8_t leaf_phase = (node_data.phase[phase] >> ctr++) & 1;
      flow += node_match[leaf].flows[leaf_phase];
    }

    return flow;
  }

